def _raises(fn, exc) -> bool:
    """`fn` MUST raise `exc`. Returning a falsy value is not the same as refusing, and a check that
    accepts either is a check that would pass on a function that silently returns None."""
    try:
        fn()
    except exc:
        return True
    except Exception:
        return False
    return False


